26	const PROCESSING_FEE = 5;
27	const CURSED_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const LOYALTY_THRESHOLD_YEARS = 2;
33	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
34	
35	const BASE_PREMIUMS: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_PREMIUM = 60;
47	
48	const calculateComponentPremium = (type: string, count: number): number =>
49	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
50	
51	const calculateItemPremium = (item: Item): number => {
52	  const base = BASE_PREMIUMS[item.type] ?? 0;
53	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
54	  const enchantmentSurcharge =
55	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
56	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
57	      : 0;
58	  return base + cursedSurcharge + enchantmentSurcharge;
59	};
60	
61	const calculatePremiums = (items: Item[]): { rawBase: number; totalWithSurcharges: number } => {
62	  const componentCounts = new Map<string, number>();
63	  let rawBase = 0;
64	  let totalWithSurcharges = 0;
65	
66	  for (const item of items) {
67	    if (COMPONENT_TYPES.has(item.type)) {
68	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
69	    } else {
70	      rawBase += BASE_PREMIUMS[item.type] ?? 0;
71	      totalWithSurcharges += calculateItemPremium(item);
72	    }
73	  }
74	
75	  for (const [type, count] of componentCounts) {
76	    const componentPremium = calculateComponentPremium(type, count);
77	    rawBase += componentPremium;
78	    totalWithSurcharges += componentPremium;
79	  }
80	
81	  return { rawBase, totalWithSurcharges };
82	};
83	
84	export function processScenario(scenario: Scenario): ScenarioOutput {
85	  const results = scenario.steps.map((step, index) => {
86	    const { rawBase, totalWithSurcharges } = calculatePremiums(step.items);
87	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? rawBase * LOYALTY_DISCOUNT_RATE : 0;
88	    const followUpDiscount = index > 0 ? rawBase * FOLLOW_UP_DISCOUNT_RATE : 0;
89	    const policyPremium = totalWithSurcharges + rawBase * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount;
90	    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
91	    return { premium };
92	  });
93	  return { results };
94	}
