export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step, index) => {
    const { rawBase, totalWithSurcharges } = calculatePremiums(step.items);
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? rawBase * LOYALTY_DISCOUNT_RATE : 0;
    const followUpDiscount = index > 0 ? rawBase * FOLLOW_UP_DISCOUNT_RATE : 0;
    const policyPremium = totalWithSurcharges + rawBase * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount;
    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

