const calculatePolicyModifier = (
  rawBase: number,
  yearsWithMHPCO: number,
  isFollowUp: boolean,
): number => {
  const firstInsurance = rawBase * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? rawBase * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = isFollowUp ? rawBase * FOLLOW_UP_DISCOUNT_RATE : 0;
  return firstInsurance - loyaltyDiscount - followUpDiscount;
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step, index) => {
    const { rawBase, totalWithSurcharges } = calculatePremiums(step.items);
    const policyModifier = calculatePolicyModifier(rawBase, scenario.customer.yearsWithMHPCO, index > 0);
    const premium = Math.ceil(totalWithSurcharges + policyModifier) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

