85	  basePremiumTotal: number,
86	  yearsWithMHPCO: number,
87	  isFollowUp: boolean,
88	): number => {
89	  const firstInsurance = basePremiumTotal * FIRST_INSURANCE_SURCHARGE_RATE;
90	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremiumTotal * LOYALTY_DISCOUNT_RATE : 0;
91	  const followUpDiscount = isFollowUp ? basePremiumTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
92	  return firstInsurance - loyaltyDiscount - followUpDiscount;
93	};
