95	export function processScenario(scenario: Scenario): ScenarioOutput {
96	  const results = scenario.steps.map((step, index) => {
97	    const { basePremiumTotal, totalWithSurcharges } = calculatePremiums(step.items);
98	    const policyModifier = calculatePolicyModifier(basePremiumTotal, scenario.customer.yearsWithMHPCO, index > 0);
99	    const premium = Math.ceil(totalWithSurcharges + policyModifier) + PROCESSING_FEE;
100	    return { premium };
101	  });
102	  return { results };
103	}
